<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentDiscipline;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentDisciplineRepository extends BaseRepository{    public function __construct(StudentDiscipline $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByIncidentType(string $incidentType): Collection    {        return $this->findByField('incident_type', $incidentType);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('incident_date', [$startDate, $endDate])->get();    }    public function getResolvedIncidents(): Collection    {        return $this->query()->where('status', 'resolved')->get();    }    public function getPendingIncidents(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function countByType(): Collection    {        return $this->query()->selectRaw('incident_type, COUNT(*) as total')->groupBy('incident_type')->get();    }    public function countByStudent(int $studentId): int    {        return $this->query()->where('student_id', $studentId)->count();    }}